/*!
 * \file navic_l5_signal_replica.cc
 * \brief This file implements functions for NavIC L5 SPS signal replica generation
 * \author GNSS-SDR developers, 2024-2025
 *
 * Ref: IRNSS SIS ICD for SPS, Version 1.1, August 2017
 * Section 4.1.1: SPS Code Generation
 *
 * PRN codes are Gold codes generated by two 10-bit MLFSRs (G1, G2):
 *   G1 polynomial: X^10 + X^3 + 1
 *   G2 polynomial: X^10 + X^9 + X^8 + X^6 + X^3 + X^2 + 1
 *   G1 initial state: all 1s
 *   G2 initial state: per-PRN from ICD Table 7
 *   Output: G1[10] XOR G2[10]  (position 10 = output stage)
 *
 * -----------------------------------------------------------------------------
 *
 * GNSS-SDR is a Global Navigation Satellite System software-defined receiver.
 * This file is part of GNSS-SDR.
 *
 * Copyright (C) 2010-2025  (see AUTHORS file for a list of contributors)
 * SPDX-License-Identifier: GPL-3.0-or-later
 *
 * -----------------------------------------------------------------------------
 */

#include "navic_l5_signal_replica.h"
#include "NAVIC_L5.h"
#include <array>
#include <cmath>

const auto AUX_CEIL = [](float x) { return static_cast<int32_t>(static_cast<int64_t>((x) + 1)); };


void navic_l5_code_gen_int(own::span<int32_t> dest, int32_t prn, uint32_t chip_shift)
{
    constexpr uint32_t code_length = 1023;

    // Validate PRN
    if (prn < 1 || prn > NAVIC_L5_NUM_SATS)
        {
            return;
        }

    // Get G2 initial condition from ICD Table 7
    const int32_t g2_init = NAVIC_L5_G2_INIT[prn];

    // G1 and G2 shift registers (10 bits each)
    // reg[0] = position 1 (input), reg[9] = position 10 (output)
    std::array<int32_t, 10> g1_reg{};
    std::array<int32_t, 10> g2_reg{};

    // Initialize G1 to all 1s (ICD Section 4.1.1, v1.1)
    for (int i = 0; i < 10; i++)
        {
            g1_reg[i] = 1;
        }

    // Initialize G2 from per-PRN table
    // ICD Table 7 lists bits as: leftmost = position 10 (output), rightmost = position 1 (input)
    // So we need to reverse the bit order: ICD bit 0 (rightmost) -> reg[0] (position 1)
    for (int i = 0; i < 10; i++)
        {
            g2_reg[i] = (g2_init >> i) & 1;
        }

    // Generate 1023 chips
    std::array<int32_t, code_length> code{};
    for (uint32_t chip = 0; chip < code_length; chip++)
        {
            // Output: XOR of G1 and G2 output stages (position 10)
            code[chip] = g1_reg[9] ^ g2_reg[9];

            // G1 feedback: positions 3 and 10 → reg[2] XOR reg[9]
            int32_t g1_feedback = g1_reg[2] ^ g1_reg[9];

            // G2 feedback: positions 2, 3, 6, 8, 9, 10
            // → reg[1] XOR reg[2] XOR reg[5] XOR reg[7] XOR reg[8] XOR reg[9]
            int32_t g2_feedback = g2_reg[1] ^ g2_reg[2] ^ g2_reg[5] ^ g2_reg[7] ^ g2_reg[8] ^ g2_reg[9];

            // Shift both registers right (position i <- position i-1)
            for (int i = 9; i > 0; i--)
                {
                    g1_reg[i] = g1_reg[i - 1];
                    g2_reg[i] = g2_reg[i - 1];
                }

            // Feed back to position 1 (reg[0])
            g1_reg[0] = g1_feedback;
            g2_reg[0] = g2_feedback;
        }

    // Apply chip shift and convert to +1/-1
    for (uint32_t i = 0; i < code_length; i++)
        {
            // 0 -> +1, 1 -> -1 (standard BPSK mapping)
            dest[i] = 1 - 2 * code[(i + chip_shift) % code_length];
        }
}


void navic_l5_code_gen_float(own::span<float> dest, int32_t prn, uint32_t chip_shift)
{
    constexpr uint32_t code_length = 1023;
    std::array<int32_t, code_length> code_int{};

    navic_l5_code_gen_int(own::span<int32_t>(code_int.data(), code_length), prn, chip_shift);

    for (uint32_t i = 0; i < code_length; i++)
        {
            dest[i] = static_cast<float>(code_int[i]);
        }
}


void navic_l5_code_gen_complex(own::span<std::complex<float>> dest, int32_t prn, uint32_t chip_shift)
{
    constexpr uint32_t code_length = 1023;
    std::array<int32_t, code_length> code_int{};

    navic_l5_code_gen_int(own::span<int32_t>(code_int.data(), code_length), prn, chip_shift);

    for (uint32_t i = 0; i < code_length; i++)
        {
            dest[i] = std::complex<float>(static_cast<float>(code_int[i]), 0.0F);
        }
}


void navic_l5_code_gen_complex_sampled(own::span<std::complex<float>> dest,
    int32_t prn,
    int32_t sampling_freq,
    uint32_t chip_shift)
{
    constexpr int32_t code_freq_basis = 1023000;  //!< NAVIC L5 code rate [chips/s]
    constexpr int32_t code_length = 1023;
    constexpr float tc = 1.0F / static_cast<float>(code_freq_basis);

    const auto samples_per_code = static_cast<int32_t>(
        static_cast<double>(sampling_freq) /
        (static_cast<double>(code_freq_basis) / static_cast<double>(code_length)));
    const float ts = 1.0F / static_cast<float>(sampling_freq);

    std::array<std::complex<float>, 1023> code_aux{};
    navic_l5_code_gen_complex(own::span<std::complex<float>>(code_aux.data(), code_length), prn, chip_shift);

    for (int32_t i = 0; i < samples_per_code; i++)
        {
            const float aux = (ts * (static_cast<float>(i) + 1)) / tc;
            int32_t code_value_index = AUX_CEIL(aux) - 1;

            if (i == samples_per_code - 1)
                {
                    dest[i] = code_aux[code_length - 1];
                }
            else
                {
                    dest[i] = code_aux[code_value_index];
                }
        }
}
